codeExamples.code:
console.log(myName);
// ReferenceError: myName is not defined
// 變數還沒宣告就使用，會直接報錯

const discount = 0.8;
const bananaPrice = 30;
let cartQuantity = 0;
cartQuantity = 3;
console.log(discount, bananaPrice, cartQuantity);

let ming = '小明';
ming = '小民';  // 合法！重新賦值
console.log(ming);

console.log(b);
let b = 10;
// ReferenceError: Cannot access 'b' before initialization
// let 的 TDZ 不讓你在宣告前使用

// 實務寫法示範：一個簡單的購物計算
const TAX_RATE = 0.05;      // 稅率不會變 → const
const PRODUCT_NAME = '鍵盤'; // 商品名稱不會變 → const
let quantity = 1;            // 數量會被使用者改變 → let
let totalPrice = 0;          // 總價會被計算更新 → let

quantity = 3;
totalPrice = 1500 * quantity * (1 + TAX_RATE);
console.log(PRODUCT_NAME, totalPrice);

